"use strict";(self.webpackChunkics_training=self.webpackChunkics_training||[]).push([[4431],{4107(e,t,i){i.r(t),i.d(t,{assets:()=>d,contentTitle:()=>l,default:()=>p,frontMatter:()=>c,metadata:()=>a,toc:()=>h});const a=JSON.parse('{"id":"advanced/practice/module-3","title":"Advanced Module 3 Practice: Quick-Close vs. Full ICS","description":"Brightpath Consulting is a 75-person government contractor with $12M in annual revenue, primarily from T&M and cost-plus contracts. Its profile for the year in question:","source":"@site/docs/advanced/practice/module-3.md","sourceDirName":"advanced/practice","slug":"/advanced/practice/module-3","permalink":"/advanced/practice/module-3","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"title":"Advanced Module 3 Practice: Quick-Close vs. Full ICS"},"sidebar":"tutorialSidebar","previous":{"title":"Advanced Module 2 Practice: CAS Disclosure Statement Alignment","permalink":"/advanced/practice/module-2"},"next":{"title":"Advanced Module 4 Practice: DCAA Audit Process End-to-End","permalink":"/advanced/practice/module-4"}}');var s=i(4848),n=i(8453),o=i(5960),r=i(5622);const c={title:"Advanced Module 3 Practice: Quick-Close vs. Full ICS"},l=void 0,d={},h=[];function u(e){const t={a:"a",hr:"hr",li:"li",p:"p",ul:"ul",...(0,n.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsxs)(o.A,{moduleId:"module3",stepId:"1",title:"Step 1: Evaluate Quick-Close Eligibility",children:[(0,s.jsx)("p",{children:(0,s.jsx)(t.p,{children:"Brightpath Consulting is a 75-person government contractor with $12M in annual revenue, primarily from T&M and cost-plus contracts. Its profile for the year in question:"})}),(0,s.jsx)("p",{children:(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsxs)(t.li,{children:["All prior ICS years (Years 1-3) have been closed with final rate agreements.",(0,s.jsx)("br",{})]}),"\n",(0,s.jsxs)(t.li,{children:["Year 4 (the current year) is the only open ICS year.",(0,s.jsx)("br",{})]}),"\n",(0,s.jsxs)(t.li,{children:["Total unsettled direct costs for Year 4: approximately $3.2M.",(0,s.jsx)("br",{})]}),"\n",(0,s.jsxs)(t.li,{children:["No DCAA system deficiencies on record; last system audit was 2 years ago with no findings.",(0,s.jsx)("br",{})]}),"\n",(0,s.jsxs)(t.li,{children:["Provisional billing rates for Year 4 were negotiated with the ACO and used throughout the year.",(0,s.jsx)("br",{})]}),"\n",(0,s.jsx)(t.li,{children:"Actual rates came in within 4% of provisional rates on all pools."}),"\n"]})}),(0,s.jsx)(r.A,{answer:"Brightpath appears to meet all four FAR 42.708 quick-close conditions: (1) No unsettled prior ICS years \u2014 Years 1-3 are all closed. Check. (2) Total unsettled direct costs are below a threshold \u2014 $3.2M is relatively modest; whether it is below the specific contracting activity threshold depends on the agency, but for a small contractor this is typically in range. (3) No known significant cost accounting or estimating system deficiencies \u2014 last audit was clean. Check. (4) ACO and DCAA would need to agree \u2014 the clean system audit, close billing-to-actual variance (under 4%), and modest dollar volume all support their agreement. Brightpath is a strong quick-close candidate.",children:(0,s.jsx)(t.p,{children:"Evaluate whether Brightpath meets the four FAR 42.708 quick-close conditions. Identify which conditions are clearly met and which depend on additional facts."})}),(0,s.jsx)(r.A,{answer:"The primary risk is that quick-close waives Brightpath's right to claim additional costs not captured in the agreed rates. With actual rates within 4% of provisional rates, the variance is small \u2014 but Brightpath should calculate whether it was net overbilled or underbilled. If actual rates are lower than provisional billing rates, Brightpath owes money back and quick-close is straightforward. If actual rates are higher (underbilled), quick-close means forfeiting that additional recovery. In this scenario, a 4% favorable variance (billing rates above actual) might mean Brightpath owes the government a refund \u2014 in which case quick-close locks that in with no downside for the contractor. But a 4% unfavorable variance (underbilled) would represent $128,000 forfeited on the $3.2M base, which is worth calculating before agreeing to quick-close.",children:(0,s.jsx)(t.p,{children:"What is the primary financial risk Brightpath takes on by electing quick-close? What calculation should it do before agreeing to proceed?"})})]}),"\n",(0,s.jsxs)(o.A,{moduleId:"module3",stepId:"2",title:"Step 2: Navigate the Quick-Close Process",children:[(0,s.jsx)("p",{children:(0,s.jsx)(t.p,{children:"Brightpath decides to request quick-close. The ACO is receptive but says DCAA needs to weigh in. DCAA's response comes back 6 weeks later: DCAA has no audit plans for Brightpath's Year 4 ICS and does not object to quick-close, but notes it discovered during a separate procurement audit that Brightpath had an unresolved timesheet policy question on Contract X (a T&M contract). DCAA says it is not a \"significant\" finding but asks the ACO to be aware."})}),(0,s.jsx)(r.A,{answer:"The timesheet policy question complicates but does not necessarily block quick-close. The key FAR 42.708 condition is 'no known significant cost accounting or estimating system deficiencies.' DCAA characterized the timesheet issue as 'not significant,' which suggests it does not rise to that level. However, the ACO may want to understand the nature of the timesheet question before agreeing to close rates. Brightpath should: (1) request a copy of the procurement audit finding or ask the ACO to describe it; (2) address the timesheet policy issue directly \u2014 either by demonstrating the policy complies with FAR 31.201-2 or by providing documentation of corrective action; (3) ask DCAA to formally confirm in writing that the issue does not constitute a significant cost accounting system deficiency. If DCAA confirms it in writing, the ACO has cover to proceed with quick-close.",children:(0,s.jsx)(t.p,{children:"Does DCAA's note about the timesheet issue block quick-close? What should Brightpath do to address this concern while keeping the quick-close process moving?"})}),(0,s.jsx)(r.A,{answer:"In the quick-close negotiation, the ACO and Brightpath agree on final rates for each indirect cost pool. These rates are typically set very close to provisional billing rates, adjusted for any variances identified in the desk review of the ICS. The ACO does not need to perform detailed testing. Brightpath provides its ICS (all standard schedules), the reconciliation to financial statements, and any supporting calculations for material rate variances. The ACO issues a Final Indirect Cost Rate Agreement (FICRA) documenting the agreed rates, which closes the year. No audit report is issued; no draft report management response is required.",children:(0,s.jsx)(t.p,{children:"Describe what the actual quick-close rate agreement negotiation looks like \u2014 what does Brightpath provide, what does the ACO do, and what document finalizes the year?"})})]}),"\n",(0,s.jsxs)(o.A,{moduleId:"module3",stepId:"3",title:"Step 3: Compare Outcomes \u2014 Quick-Close vs. Full Audit",children:[(0,s.jsx)("p",{children:(0,s.jsx)(t.p,{children:"As a comparison exercise, Brightpath's controller is building a business case to present to management about whether quick-close was the right choice. She estimates that if the year went through full audit: the audit would take 3-4 years, DCAA would likely question $45,000 in travel costs (which the controller believes are 70% defensible), and there is a 30% chance DCAA would also identify a $25,000 questioned cost related to consultant invoices."})}),(0,s.jsx)(r.A,{answer:"Expected value of full audit questioned costs: Travel: $45,000 questioned, 30% likely to be sustained (30% not defensible) = $13,500 expected disallowance. Consultant: $25,000 \xd7 30% probability \xd7 50% sustain rate (conservative) = $3,750 expected disallowance. Total expected disallowance under full audit: approximately $17,250. Under quick-close, the rates are agreed without these being tested \u2014 so if the controller's estimates are accurate, quick-close likely results in no disallowance on these items. The advantage: ~$17,250 in avoided disallowances plus 2-3 years faster rate finality, freeing contracts for closeout and reducing administrative burden. The risk: if there are additional unidentified issues, quick-close forfeits the right to negotiate them.",children:(0,s.jsx)(t.p,{children:"Using the controller's estimates, calculate the expected value of questioned costs under a full audit. Does the analysis support the quick-close decision? What factors does the pure dollar calculation miss?"})}),(0,s.jsx)(r.A,{answer:"The dollar analysis misses several important non-financial factors: (1) Time value: 3-4 years of open ICS year means 3-4 years of administrative burden, open contracts that cannot be closed, and potential document retention obligations. (2) Management attention: full audits require significant staff time to respond to IRs, support field visits, and prepare management responses. This time has a real cost even if it does not appear in the questioned-cost calculation. (3) Certainty: quick-close gives Brightpath certain, final rates immediately. Full audit introduces 3-4 years of uncertainty about cash flow from final billing reconciliation. (4) Relationship with DCAA: proactively supporting quick-close for low-risk years can build goodwill with DCAA and the ACO, which may benefit Brightpath on future procurements or audits.",children:(0,s.jsx)(t.p,{children:"What non-financial factors does the pure dollar calculation miss? List at least three reasons why quick-close might still be the right choice even if the expected disallowance under a full audit is relatively small."})})]}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.a,{href:"/advanced/flashcards/module-3",children:"\u2190 Flashcards"})," | ",(0,s.jsx)(t.a,{href:"/advanced/training/module-4",children:"Next Module \u2192"})]})]})}function p(e={}){const{wrapper:t}={...(0,n.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(u,{...e})}):u(e)}},5622(e,t,i){i.d(t,{A:()=>n});var a=i(6540),s=i(4848);function n(e){var t=e.children,i=e.answer,n=(0,a.useState)(!1),o=n[0],r=n[1];return(0,s.jsxs)("div",{style:{marginTop:8},children:[(0,s.jsx)("div",{children:t}),(0,s.jsx)("button",{style:{marginTop:8},onClick:function(){return r(!o)},children:o?"Hide answer":"Show answer"}),o&&(0,s.jsx)("div",{style:{marginTop:8,background:"#f7f7f7",padding:8,borderRadius:4},children:i})]})}},5960(e,t,i){i.d(t,{A:()=>n});var a=i(6540),s=i(4848);function n(e){e.moduleId,e.stepId;var t=e.title,i=e.children,n=(0,a.useState)(!1),o=n[0],r=n[1];return(0,s.jsxs)("div",{style:{border:"1px solid #eee",padding:12,borderRadius:6,marginBottom:12},children:[(0,s.jsxs)("div",{style:{display:"flex",justifyContent:"space-between",alignItems:"center"},children:[(0,s.jsx)("strong",{children:t}),o?(0,s.jsx)("button",{onClick:function(){return r(!1)},children:"Hide"}):(0,s.jsx)("button",{onClick:function(){return r(!0)},children:"Reveal"})]}),o&&(0,s.jsx)("div",{style:{marginTop:12},children:i})]})}},8453(e,t,i){i.d(t,{R:()=>o,x:()=>r});var a=i(6540);const s={},n=a.createContext(s);function o(e){const t=a.useContext(n);return a.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:o(e.components),a.createElement(n.Provider,{value:t},e.children)}}}]);